import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




import { MotionKeyframes, useAnimationKey } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';
import { Clickable } from '@ggui-ai/design/interact';

const StockCard = ({ stock }: { stock: NonNullable<Props['stocks']>[0] }) => {
  const flashKey = useAnimationKey(stock.price);
  const isPositive = (stock.change ?? 0) >= 0;
  const color = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

  return (
    <Card 
      key={flashKey} 
      padding="var(--ggui-spacing-4)" 
      style={{
        animation: animation.flash,
        '--ggui-flash-color': isPositive ? 'var(--ggui-color-success-100)' : 'var(--ggui-color-error-100)',
        border: `1px solid ${color}`
      } as React.CSSProperties}
    >
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="center">
          <Heading level={3}>{stock.symbol}</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{stock.name}</Text>
        </Row>
        <Heading level={2}>${stock.price?.toFixed(2)}</Heading>
        <Row gap="var(--ggui-spacing-2)" align="center">
          <Text style={{ color }} weight="semibold">
            {isPositive ? '+' : ''}{stock.change?.toFixed(2)} ({isPositive ? '+' : ''}{stock.changePercent?.toFixed(2)}%)
          </Text>
          <Icon name={isPositive ? 'arrow-up' : 'arrow-down'} color={color} size={16} />
        </Row>
      </Stack>
    </Card>
  );
};


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocks, setStocks] = useState(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState(new Date());

  useEffect(() => {
    const update = priceUpdate.latest;
    if (update && update.symbol) {
      setStocks((prev) => prev.map(s => s.symbol === update.symbol ? { ...s, ...update } : s));
      setLastUpdated(new Date());
    }
  }, [priceUpdate.latest]);

  const sortedStocks = useMemo(() => stocks.filter(s => s.symbol), [stocks]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Stack align="end">
            <Text variant="label">Last Updated</Text>
            <Text variant="bodySmall">{lastUpdated.toLocaleTimeString()}</Text>
          </Stack>
        </Row>

        <Box>
          <div style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', 
            gap: 'var(--ggui-spacing-4)' 
          }}>
            {sortedStocks.map((stock) => (
              <StockCard key={stock.symbol} stock={stock} />
            ))}
          </div>
        </Box>
      </Stack>
    </Container>
  );
}
